CustomField.formula:
AND(
  OR(
    CONTAINS(FEC_Follow_Up_User__c, CASESAFEID($User.Id)),
    CONTAINS(FEC_Follow_Up_User__c, $User.Id)
  ),
  OR(
    AND(
      OR(ISPICKVAL(Status, "Open"), ISPICKVAL(Status, "Pending")),
      OwnerId <> $User.Id
    ),
    NOT(OR(ISPICKVAL(Status, "Open"), ISPICKVAL(Status, "Pending")))
  )
)
